solution_code:
#include <iostream>

template <typename T>
T minVal(T a, T b)
{
    return (a < b) ? a : b;
}

int main()
{
    double a, b;
    std::cin >> a >> b;
    std::cout << "deduced: "  << minVal(a, b)         << '\n';
    std::cout << "explicit: " << minVal<double>(a, b)  << '\n';
    return 0;
}

