#include <iostream>

template <typename T>
T average(T a, T b)
{
    return (a + b) / 2;
}

int main()
{
    // Fixed: use <double> so division is floating-point
    std::cout << "average: " << average<double>(4.0, 5.0) << '\n';
    return 0;
}
